import{_ as r,M as n,p,q as o,Q as a,N as t,a1 as e,t as i}from"./framework-7d8e42ec.js";const c="/images/micro/微前端模式.png",h="/images/micro/微应用维度.png",l="/images/micro/微模块维度.png",d="/images/micro/乾坤与sspa.png",m="/images/micro/基座模式微前端流程图.png",u="/images/micro/micro-app-概念图.png",g="/images/micro/micro-app-优势对比.png",_="/images/micro/micro-app-流程图.png",f={},b=e('<h1 id="🔨-如何实现微前端" tabindex="-1"><a class="header-anchor" href="#🔨-如何实现微前端" aria-hidden="true">#</a> 🔨 如何实现微前端</h1><h2 id="微前端模式" tabindex="-1"><a class="header-anchor" href="#微前端模式" aria-hidden="true">#</a> 微前端模式</h2><p>微前端的模式大致如下分布</p><p><img src="'+c+'" alt="微前端模式"></p><h2 id="自组织模式" tabindex="-1"><a class="header-anchor" href="#自组织模式" aria-hidden="true">#</a> 自组织模式</h2><p>应用之间是平等的，不存在相互管理的模式。设计难度大，不方便实施，但是通用度高。</p><h2 id="基座模式" tabindex="-1"><a class="header-anchor" href="#基座模式" aria-hidden="true">#</a> 基座模式</h2><div class="custom-container warning"><p class="custom-container-title">WARNING</p><p>我们的业务框架也是基座模式，但使用的不是当前二者，当前文档只是帮助大家理解基座模式</p></div><p>通过一个主应用，来管理其它应用。设计难度小，方便实践，但是通用度低。</p><p>代表：qiankun、single-spa</p><p>虽然 qiankun 与 single-spa 都是基座模式，但是本身的理念又有些许不同</p><h3 id="微应用维度-qiankun" tabindex="-1"><a class="header-anchor" href="#微应用维度-qiankun" aria-hidden="true">#</a> 微应用维度 Qiankun</h3><p>它主要解决的是：如何安全、快速的把多个分散的项目集中起来的问题</p><p><img src="'+h+'" alt="微应用维度"></p><p>所有这些特性都是服务于“微应用加载器”这个定位</p><h3 id="微模块维度-single-spa" tabindex="-1"><a class="header-anchor" href="#微模块维度-single-spa" aria-hidden="true">#</a> 微模块维度 Single-spa</h3><p>它主要解决的是：如何实现前端的“微服务化”，从而让应用、组件、逻辑都成为可共享的微服务</p><p><img src="'+l+'" alt="微模块维度"></p><p>在 single-spa 看来微前端有三种类型：</p><ul><li>微应用</li><li>微组件</li><li>微模块</li></ul><p>实际上 single-spa 要求它们都以 SystemJS 的形式打包<br> 换句话说它们本质上都是 <strong style="color:#ff3040;">微模块</strong></p><h3 id="谁才是微前端" tabindex="-1"><a class="header-anchor" href="#谁才是微前端" aria-hidden="true">#</a> 谁才是微前端？</h3><p>要讨论这个问题，我们要先想清楚以下两点的区别：</p><ul><li>微应用加载器：“微”的粒度是应用，也就是HTML（或main.js），它只能做到应用级别的分享</li><li>微模块加载器：“微”的粒度是模块，也就是JS模块，它能做到模块级别的分享</li></ul><p>所以，它们的区别就是微服务的粒度，乾坤的所能服务的粒度是应用级别，而 single-spa 则是模块级别。</p><p>那么谁才是微前端呢？答案是：都是。<br> 因为它们都能将前端进行拆分，只是拆分的粒度不同罢了。但要说谁的微前端更极致，那肯定是 single-spa。</p><h3 id="立意及区别" tabindex="-1"><a class="header-anchor" href="#立意及区别" aria-hidden="true">#</a> 立意及区别</h3><p>乾坤基于single-spa，加强了微应用集成能力，却抛弃了微模块的能力，为什么要这么做呢？我们要想清楚这两个框架出现的背景：</p><ul><li><p>乾坤：</p><blockquote><p>阿里内部有大量年久失修的项目，业务侧急需工具去把他们快速、安全的集成到一起。<br> 在这个角度，乾坤根本没有做模块联邦的需求，它的需求仅仅是如何快速、安全的把项目集成起来。<br> 所以乾坤是想做一个微前端工具。</p></blockquote></li><li><p>single-spa：</p><blockquote><p>学习后端的微服务，实现前端的微服务化，让应用、组件以及逻辑都成为可共享的微服务，实现真正意义上的微前端。</p></blockquote></li></ul><h3 id="对比图" tabindex="-1"><a class="header-anchor" href="#对比图" aria-hidden="true">#</a> 对比图</h3><p><img src="'+d+'" alt="乾坤与sspa"></p><h3 id="single-spa-加载原理流程图" tabindex="-1"><a class="header-anchor" href="#single-spa-加载原理流程图" aria-hidden="true">#</a> single-spa 加载原理流程图</h3><p>原 pdf 已给到前端同事</p><p><img src="'+m+'" alt="基座模式微前端流程图"></p><h2 id="模块加载模式-module-federation" tabindex="-1"><a class="header-anchor" href="#模块加载模式-module-federation" aria-hidden="true">#</a> 模块加载模式 Module Federation</h2><p>我个人认为未来的微前端应该是以模块维度进行搭建的，更极致的模块加载模式也不是 single-spa，而是 webpack5 提供给我们的<strong style="color:#ff3040;">模块联邦</strong>。<br> 由于时间关系，以及这是较新的技术，试错成本、开发成本、维护成本，都将是巨大的。</p><p>我也尝试了完全使用模块联邦去做微前端，但是已发现的问题就导致了无法进行下去，如：</p><ul><li>无法动态引入远程的模块</li><li>产生了循环引用的问题</li></ul><h2 id="microapp-基座模式" tabindex="-1"><a class="header-anchor" href="#microapp-基座模式" aria-hidden="true">#</a> MicroApp 基座模式</h2>',39),x={class:"custom-container tip"},k=a("p",{class:"custom-container-title"},"TIP",-1),q=i("此方案为我们业务框架所采用的，详见 "),N={href:"https://micro-zoe.github.io/micro-app/",target:"_blank",rel:"noopener noreferrer"},S=i("MicroApp"),v=e('<p>micro-app并没有沿袭single-spa的思路，而是<strong style="color:purple;">借鉴了WebComponent的思想，通过CustomElement结合自定义的ShadowDom，将微前端封装成一个类WebComponent组件，从而实现微前端的组件化渲染。</strong></p><p>并且由于自定义ShadowDom的隔离特性，micro-app不需要像single-spa和qiankun一样要求子应用修改渲染逻辑并暴露出方法，也不需要修改webpack配置，是目前市面上接入微前端成本最低的方案。</p><h3 id="概念图" tabindex="-1"><a class="header-anchor" href="#概念图" aria-hidden="true">#</a> 概念图</h3><p><img src="'+u+'" alt="micro-app-概念图"></p><h3 id="与-qiankun、sspa-的对比" tabindex="-1"><a class="header-anchor" href="#与-qiankun、sspa-的对比" aria-hidden="true">#</a> 与 qiankun、sspa 的对比</h3><p><img src="'+g+'" alt="micro-app-优势对比"></p><h3 id="流程图" tabindex="-1"><a class="header-anchor" href="#流程图" aria-hidden="true">#</a> 流程图</h3><p><img src="'+_+'" alt="micro-app-流程图"></p>',8);function w(M,y){const s=n("ExternalLinkIcon");return p(),o("div",null,[b,a("div",x,[k,a("p",null,[q,a("a",N,[S,t(s)])])]),v])}const E=r(f,[["render",w],["__file","scheme.html.vue"]]);export{E as default};
